class Solution {
    public double minTime(int n, int k, int m, int[] time, double[] mul) {
        if (k == 1) return n == 1 ? time[0] * mul[0] : -1.0;
        int fullMask = (1 << n) - 1;
        double[][] dp = new double[fullMask + 1][m];
        for (double[] row : dp) Arrays.fill(row, Double.MAX_VALUE);
        dp[0][0] = 0.0;
        for (int mask = 0; mask <= fullMask; mask++) {
            for (int stage = 0; stage < m; stage++) {
                if (dp[mask][stage] == Double.MAX_VALUE) continue;
                int left = fullMask ^ mask;
                for (int sub = left; sub > 0; sub = (sub - 1) & left) {
                    if (Integer.bitCount(sub) > k) continue;
                    int maxT = 0;
                    for (int i = 0; i < n; i++) if ((sub & (1 << i)) != 0) maxT = Math.max(maxT, time[i]);
                    double cross = maxT * mul[stage];
                    int newStage = (stage + (int) Math.floor(cross)) % m;
                    double newTime = dp[mask][stage] + cross;
                    if ((mask | sub) == fullMask) {
                        if (newTime < dp[fullMask][newStage]) dp[fullMask][newStage] = newTime;
                        continue;
                    }
                    for (int r = 0; r < n; r++) {
                        if ((mask & (1 << r)) == 0) continue;
                        double back = time[r] * mul[newStage];
                        int retStage = (newStage + (int) Math.floor(back)) % m;
                        double total = newTime + back;
                        if (total < dp[mask | sub][retStage]) dp[mask | sub][retStage] = total;
                    }
                }
            }
        }
        double ans = Double.MAX_VALUE;
        for (double v : dp[fullMask]) if (v < ans) ans = v;
        return ans == Double.MAX_VALUE ? -1.0 : ans;
    }
}
